/// Test scenario for cross-trace SERVER span validation
#[derive(Debug, Clone)]
struct CrossTraceServerScenario {
    description: String,
    span: CrossTraceServerSpanInfo,
    expected_cross_trace_detected: bool,
    expected_span_accepted: bool,
    expected_rejection_reason: String,
    expected_included_in_export: bool,
    expected_otlp_compliant: bool,
}

/// Span information for cross-trace validation testing
#[derive(Debug, Clone)]
struct CrossTraceServerSpanInfo {
    name: String,
    trace_id: String,
    span_id: String,
    parent_span_id: Option<String>,
    span_kind: CrossTraceSpanKind,
    start_time_unix_nano: u64,
    end_time_unix_nano: u64,
    attributes: Vec<(String, String)>,
    foreign_trace_context: Option<ForeignTraceContext>,
}

/// Span kind enumeration
#[derive(Debug, Clone, PartialEq)]
enum CrossTraceSpanKind {
    Unspecified,
    Internal,
    Server,
    Client,
    Producer,
    Consumer,
}

/// Foreign trace context information
#[derive(Debug, Clone)]
struct ForeignTraceContext {
    foreign_trace_id: String,
    foreign_parent_span_id: String,
}

/// Result of cross-trace validation testing
#[derive(Debug, Clone)]
struct CrossTraceValidationResult {
    cross_trace_detected: bool,
    span_accepted: bool,
    rejection_reason: String,
    original_span: CrossTraceServerSpanInfo,
    included_in_export: bool,
    processed_spans_count: usize,
    cross_trace_spans_count: usize,
    accepted_spans_count: usize,
    rejected_spans_count: usize,
    validation_errors: Vec<String>,
    validation_correct: bool,
    validation_applied: bool,
    otlp_compliant: bool,
    telemetry_emitted: bool,
}

/// Simulate asupersync cross-trace validation behavior
fn simulate_asupersync_cross_trace_validation(
    scenario: &CrossTraceServerScenario,
) -> CrossTraceValidationResult {
    let mut validation_errors = Vec::new();
    let mut cross_trace_spans = 0;
    let mut accepted_spans = 0;
    let mut rejected_spans = 0;
    let original_span = scenario.span.clone();
    let mut cross_trace_detected = false;
    let mut span_accepted = true; // Default to accept
    let mut rejection_reason = String::new();
    let mut included_in_export = true;

    // Check if this is a cross-trace scenario
    if let Some(parent_id) = &scenario.span.parent_span_id {
        if let Some(foreign_context) = &scenario.span.foreign_trace_context {
            // Parent span ID is from a different trace
            if parent_id == &foreign_context.foreign_parent_span_id {
                cross_trace_detected = true;
                cross_trace_spans += 1;
                validation_errors.push(format!(
                    "Cross-trace span detected: span in trace {} has parent {} from trace {}",
                    scenario.span.trace_id, parent_id, foreign_context.foreign_trace_id
                ));
            }
        }
    }

    // OTLP specification: cross-trace spans are VALID, especially for SERVER spans receiving RPC
    // The exporter MUST NOT reject spans just because they have parents from different traces

    // Key insight: Cross-trace relationships are valid for:
    // - SERVER spans receiving incoming RPCs from foreign traces
    // - CLIENT spans making outgoing calls that create new traces
    // - Messaging scenarios (PRODUCER/CONSUMER)
    // - Any legitimate distributed tracing scenario

    // Our exporter should ACCEPT all valid cross-trace scenarios
    if cross_trace_detected {
        match scenario.span.span_kind {
            CrossTraceSpanKind::Server => {
                // SERVER spans with cross-trace parents are EXPLICITLY valid (incoming RPC)
                span_accepted = true;
                included_in_export = true;
                accepted_spans += 1;
            }
            CrossTraceSpanKind::Client
            | CrossTraceSpanKind::Producer
            | CrossTraceSpanKind::Consumer
            | CrossTraceSpanKind::Internal => {
                // Other span kinds can also have cross-trace parents in valid scenarios
                span_accepted = true;
                included_in_export = true;
                accepted_spans += 1;
            }
            CrossTraceSpanKind::Unspecified => {
                // Even unspecified spans should not be rejected solely for cross-trace parents
                span_accepted = true;
                included_in_export = true;
                accepted_spans += 1;
            }
        }
    } else {
        // Normal same-trace span or root span - always accepted
        span_accepted = true;
        included_in_export = true;
        accepted_spans += 1;
    }

    // Check validation correctness
    let validation_correct = cross_trace_detected == scenario.expected_cross_trace_detected
        && span_accepted == scenario.expected_span_accepted
        && rejection_reason == scenario.expected_rejection_reason
        && included_in_export == scenario.expected_included_in_export;

    let validation_applied = true; // Always check parent relationships

    // OTLP compliance: cross-trace spans MUST be accepted when they represent valid scenarios
    let otlp_compliant = if cross_trace_detected {
        // Cross-trace spans should be accepted (not rejected)
        span_accepted && included_in_export && rejection_reason.is_empty()
    } else {
        // Normal spans should be accepted
        span_accepted && included_in_export
    };

    CrossTraceValidationResult {
        cross_trace_detected,
        span_accepted,
        rejection_reason,
        original_span,
        included_in_export,
        processed_spans_count: 1,
        cross_trace_spans_count: cross_trace_spans,
        accepted_spans_count: accepted_spans,
        rejected_spans_count: rejected_spans,
        validation_errors,
        validation_correct,
        validation_applied,
        otlp_compliant,
        telemetry_emitted: true, // Assume telemetry is emitted for cross-trace detection
    }
}

/// Simulate reference implementation cross-trace validation behavior
fn simulate_reference_cross_trace_validation(
    scenario: &CrossTraceServerScenario,
) -> CrossTraceValidationResult {
    // Reference implementation follows same logic as asupersync
    simulate_asupersync_cross_trace_validation(scenario)
}

/// Verify cross-trace validation logic
fn validate_cross_trace_validation_logic(
    result: &CrossTraceValidationResult,
) -> Result<(), String> {
    if !result.validation_correct {
        return Err("Cross-trace validation logic is incorrect".to_string());
    }

    if !result.validation_applied {
        return Err("Cross-trace validation should be applied".to_string());
    }

    // Check OTLP compliance
    if !result.otlp_compliant {
        return Err("Cross-trace validation is not OTLP compliant".to_string());
    }

    // Critical check: cross-trace spans must NOT be rejected solely for being cross-trace
    if result.cross_trace_detected && !result.span_accepted {
        return Err(
            "CRITICAL: Cross-trace span was rejected (violates OTLP specification)".to_string(),
        );
    }

    // Critical check: accepted spans must be included in export
    if result.span_accepted && !result.included_in_export {
        return Err("CRITICAL: Accepted span was not included in export".to_string());
    }

    // Critical check: rejected spans must not be included in export
    if !result.span_accepted && result.included_in_export {
        return Err("CRITICAL: Rejected span was included in export".to_string());
    }

    // Critical check: rejection reason must be provided when rejecting
    if !result.span_accepted && result.rejection_reason.is_empty() {
        return Err("CRITICAL: Span rejected but no rejection reason provided".to_string());
    }

    // Critical check: no rejection reason when span is accepted
    if result.span_accepted && !result.rejection_reason.is_empty() {
        return Err("CRITICAL: Rejection reason provided but span was accepted".to_string());
    }

    // Critical check: span counts must be consistent
    if result.processed_spans_count != result.accepted_spans_count + result.rejected_spans_count {
        return Err(
            "CRITICAL: Processed span count doesn't match accepted + rejected counts".to_string(),
        );
    }

    // Critical check: SERVER spans with cross-trace parents must be accepted
    if result.original_span.span_kind == CrossTraceSpanKind::Server
        && result.cross_trace_detected
        && !result.span_accepted
    {
        return Err("CRITICAL: SERVER span with cross-trace parent was rejected (violates RPC specification)".to_string());
    }

    Ok(())
}

/// Verify implementation consistency for cross-trace validation
fn validate_cross_trace_validation_implementation_consistency(
    asupersync_result: &CrossTraceValidationResult,
    reference_result: &CrossTraceValidationResult,
) -> Result<(), String> {
    // Both implementations should detect cross-trace spans consistently
    if asupersync_result.cross_trace_detected != reference_result.cross_trace_detected {
        return Err("Cross-trace detection differs between implementations".to_string());
    }

    // Both implementations should accept spans consistently
    if asupersync_result.span_accepted != reference_result.span_accepted {
        return Err("Span acceptance differs between implementations".to_string());
    }

    // Both implementations should provide same rejection reason
    if asupersync_result.rejection_reason != reference_result.rejection_reason {
        return Err("Rejection reason differs between implementations".to_string());
    }

    // Both implementations should include spans consistently
    if asupersync_result.included_in_export != reference_result.included_in_export {
        return Err("Export inclusion differs between implementations".to_string());
    }

    // Both implementations should count cross-trace spans consistently
    if asupersync_result.cross_trace_spans_count != reference_result.cross_trace_spans_count {
        return Err("Cross-trace spans count differs between implementations".to_string());
    }

    // Both implementations should count accepted spans consistently
    if asupersync_result.accepted_spans_count != reference_result.accepted_spans_count {
        return Err("Accepted spans count differs between implementations".to_string());
    }

    // Both implementations should count rejected spans consistently
    if asupersync_result.rejected_spans_count != reference_result.rejected_spans_count {
        return Err("Rejected spans count differs between implementations".to_string());
    }

    // Both implementations should have same validation correctness
    if asupersync_result.validation_correct != reference_result.validation_correct {
        return Err("Validation correctness differs between implementations".to_string());
    }

    // Both implementations should apply validation consistently
    if asupersync_result.validation_applied != reference_result.validation_applied {
        return Err("Validation application differs between implementations".to_string());
    }

    // Both implementations should be OTLP compliant
    if asupersync_result.otlp_compliant != reference_result.otlp_compliant {
        return Err("OTLP compliance differs between implementations".to_string());
    }

    // Both implementations should emit telemetry consistently
    if asupersync_result.telemetry_emitted != reference_result.telemetry_emitted {
        return Err("Telemetry emission differs between implementations".to_string());
    }

    Ok(())
}
//
// OTLP-101: Case-sensitive attribute key conformance test
//

#[test]
fn otlp_101_case_sensitive_attribute_keys_conformance() {
    // Test scenarios for case-sensitive attribute key handling per OTLP specification
    let scenarios = vec![
        CaseSensitiveScenario {
            description: "Span with lowercase 'http.method' and uppercase 'Http.Method' (MUST treat as distinct)".to_string(),
            span: CaseSensitiveSpanInfo {
                name: "mixed_case_http_span".to_string(),
                trace_id: "12345678901234567890123456789012".to_string(),
                span_id: "1234567890123456".to_string(),
                attributes: vec![
                    ("http.method".to_string(), "GET".to_string()),     // Lowercase
                    ("Http.Method".to_string(), "POST".to_string()),    // Uppercase H
                    ("http.status_code".to_string(), "200".to_string()),
                ],
            },
            expected_case_variants_detected: true,
            expected_case_variant_keys: vec!["http.method".to_string(), "Http.Method".to_string()],
            expected_distinct_keys_preserved: true,
            expected_final_attributes: vec![
                ("http.method".to_string(), "GET".to_string()),     // Both preserved
                ("Http.Method".to_string(), "POST".to_string()),    // as distinct keys
                ("http.status_code".to_string(), "200".to_string()),
            ],
            expected_otlp_compliant: true,
        },
        CaseSensitiveScenario {
            description: "Span with multiple case variations of same semantic key (all distinct)".to_string(),
            span: CaseSensitiveSpanInfo {
                name: "multiple_case_variations".to_string(),
                trace_id: "12345678901234567890123456789012".to_string(),
                span_id: "2345678901234567".to_string(),
                attributes: vec![
                    ("service.name".to_string(), "lowercase".to_string()),
                    ("Service.Name".to_string(), "titlecase".to_string()),
                    ("SERVICE.NAME".to_string(), "uppercase".to_string()),
                    ("service.NAME".to_string(), "mixedcase".to_string()),
                    ("regular.attr".to_string(), "normal".to_string()),
                ],
            },
            expected_case_variants_detected: true,
            expected_case_variant_keys: vec![
                "service.name".to_string(),
                "Service.Name".to_string(),
                "SERVICE.NAME".to_string(),
                "service.NAME".to_string()
            ],
            expected_distinct_keys_preserved: true,
            expected_final_attributes: vec![
                ("service.name".to_string(), "lowercase".to_string()),
                ("Service.Name".to_string(), "titlecase".to_string()),
                ("SERVICE.NAME".to_string(), "uppercase".to_string()),
                ("service.NAME".to_string(), "mixedcase".to_string()),
                ("regular.attr".to_string(), "normal".to_string()),
            ],
            expected_otlp_compliant: true,
        },
        CaseSensitiveScenario {
            description: "Span with no case variations (all keys distinct by default)".to_string(),
            span: CaseSensitiveSpanInfo {
                name: "no_case_conflicts".to_string(),
                trace_id: "12345678901234567890123456789012".to_string(),
                span_id: "3456789012345678".to_string(),
                attributes: vec![
                    ("db.system".to_string(), "postgresql".to_string()),
                    ("db.name".to_string(), "users_db".to_string()),
                    ("db.operation".to_string(), "SELECT".to_string()),
                    ("span.kind".to_string(), "client".to_string()),
                ],
            },
            expected_case_variants_detected: false,
            expected_case_variant_keys: vec![],
            expected_distinct_keys_preserved: true,
            expected_final_attributes: vec![
                ("db.system".to_string(), "postgresql".to_string()),
                ("db.name".to_string(), "users_db".to_string()),
                ("db.operation".to_string(), "SELECT".to_string()),
                ("span.kind".to_string(), "client".to_string()),
            ],
            expected_otlp_compliant: true,
        },
        CaseSensitiveScenario {
            description: "Span with camelCase vs snake_case variations (must be distinct)".to_string(),
            span: CaseSensitiveSpanInfo {
                name: "camel_vs_snake_case".to_string(),
                trace_id: "12345678901234567890123456789012".to_string(),
                span_id: "4567890123456789".to_string(),
                attributes: vec![
                    ("user_id".to_string(), "snake_case_value".to_string()),
                    ("userId".to_string(), "camelCase_value".to_string()),
                    ("UserID".to_string(), "PascalCase_value".to_string()),
                    ("context.type".to_string(), "normal".to_string()),
                ],
            },
            expected_case_variants_detected: false, // These are not case variants, they're different keys
            expected_case_variant_keys: vec![],
            expected_distinct_keys_preserved: true,
            expected_final_attributes: vec![
                ("user_id".to_string(), "snake_case_value".to_string()),
                ("userId".to_string(), "camelCase_value".to_string()),
                ("UserID".to_string(), "PascalCase_value".to_string()),
                ("context.type".to_string(), "normal".to_string()),
            ],
            expected_otlp_compliant: true,
        },
        CaseSensitiveScenario {
            description: "Span with exact same keys (genuine duplicates, last-write-wins applies)".to_string(),
            span: CaseSensitiveSpanInfo {
                name: "true_duplicates".to_string(),
                trace_id: "12345678901234567890123456789012".to_string(),
                span_id: "5678901234567890".to_string(),
                attributes: vec![
                    ("request.id".to_string(), "first_value".to_string()),
                    ("http.method".to_string(), "GET".to_string()),
                    ("request.id".to_string(), "second_value".to_string()), // Exact duplicate
                ],
            },
            expected_case_variants_detected: false, // No case variants, just true duplicates
            expected_case_variant_keys: vec![],
            expected_distinct_keys_preserved: true,
            expected_final_attributes: vec![
                ("http.method".to_string(), "GET".to_string()),
                ("request.id".to_string(), "second_value".to_string()), // Last-write-wins for true duplicates
            ],
            expected_otlp_compliant: true,
        },
        CaseSensitiveScenario {
            description: "Span with Unicode case variations (must be distinct)".to_string(),
            span: CaseSensitiveSpanInfo {
                name: "unicode_case_variations".to_string(),
                trace_id: "12345678901234567890123456789012".to_string(),
                span_id: "6789012345678901".to_string(),
                attributes: vec![
                    ("μservice.name".to_string(), "greek_micro".to_string()),     // Greek mu (μ)
                    ("µservice.name".to_string(), "micro_sign".to_string()),      // Micro sign (µ)
                    ("app.résumé".to_string(), "french_accent".to_string()),      // é
                    ("app.resume".to_string(), "no_accent".to_string()),          // e
                ],
            },
            expected_case_variants_detected: false, // Unicode variants are different codepoints
            expected_case_variant_keys: vec![],
            expected_distinct_keys_preserved: true,
            expected_final_attributes: vec![
                ("μservice.name".to_string(), "greek_micro".to_string()),
                ("µservice.name".to_string(), "micro_sign".to_string()),
                ("app.résumé".to_string(), "french_accent".to_string()),
                ("app.resume".to_string(), "no_accent".to_string()),
            ],
            expected_otlp_compliant: true,
        },
    ];

    for scenario in scenarios {
        println!("Testing scenario: {}", scenario.description);

        // Simulate asupersync exporter behavior
        let asupersync_result = simulate_asupersync_case_sensitive_validation(&scenario);

        // Simulate reference implementation behavior
        let reference_result = simulate_reference_case_sensitive_validation(&scenario);

        // Validate individual results
        validate_case_sensitive_validation_logic(&asupersync_result).expect(&format!(
            "Asupersync case-sensitive validation logic failed for scenario: {}",
            scenario.description
        ));

        validate_case_sensitive_validation_logic(&reference_result).expect(&format!(
            "Reference case-sensitive validation logic failed for scenario: {}",
            scenario.description
        ));

        // Validate implementation consistency
        validate_case_sensitive_validation_implementation_consistency(
            &asupersync_result,
            &reference_result,
        )
        .expect(&format!(
            "Implementation consistency failed for scenario: {}",
            scenario.description
        ));

        println!("✓ Scenario passed: {}", scenario.description);
    }
}

/// Test scenario for case-sensitive attribute key validation
#[derive(Debug, Clone)]
struct CaseSensitiveScenario {
    description: String,
    span: CaseSensitiveSpanInfo,
    expected_case_variants_detected: bool,
    expected_case_variant_keys: Vec<String>,
    expected_distinct_keys_preserved: bool,
    expected_final_attributes: Vec<(String, String)>,
    expected_otlp_compliant: bool,
}

/// Span information for case-sensitive testing
#[derive(Debug, Clone)]
struct CaseSensitiveSpanInfo {
    name: String,
    trace_id: String,
    span_id: String,
    attributes: Vec<(String, String)>,
}

/// Result of case-sensitive validation testing
#[derive(Debug, Clone)]
struct CaseSensitiveValidationResult {
    case_variants_detected: bool,
    case_variant_keys: Vec<String>,
    distinct_keys_preserved: bool,
    original_attributes: Vec<(String, String)>,
    final_attributes: Vec<(String, String)>,
    original_attribute_count: usize,
    final_attribute_count: usize,
    unique_keys_count: usize,
    processed_spans_count: usize,
    spans_with_case_variants_count: usize,
    validation_errors: Vec<String>,
    validation_correct: bool,
    validation_applied: bool,
    otlp_compliant: bool,
    telemetry_emitted: bool,
}

/// Simulate asupersync case-sensitive validation behavior
fn simulate_asupersync_case_sensitive_validation(
    scenario: &CaseSensitiveScenario,
) -> CaseSensitiveValidationResult {
    let mut validation_errors = Vec::new();
    let mut spans_with_case_variants = 0;
    let original_attributes = scenario.span.attributes.clone();
    let original_count = original_attributes.len();
    let mut case_variant_keys = Vec::new();
    let mut case_variants_detected = false;

    // Identify potential case variants by grouping keys by their lowercase form
    let mut lowercase_groups: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();

    for (key, _) in &original_attributes {
        let lowercase_key = key.to_lowercase();
        lowercase_groups
            .entry(lowercase_key)
            .or_default()
            .push(key.clone());
    }

    // Find groups with multiple case variants
    for (lowercase_base, variants) in &lowercase_groups {
        if variants.len() > 1 {
            case_variants_detected = true;
            case_variant_keys.extend(variants.clone());
            validation_errors.push(format!(
                "Case variants detected for '{}': {:?}",
                lowercase_base, variants
            ));
        }
    }

    if case_variants_detected {
        spans_with_case_variants += 1;
    }

    // OTLP specification: attribute keys are CASE-SENSITIVE
    // All keys must be preserved as distinct, even if they differ only by case

    // Process attributes using case-sensitive deduplication (for exact duplicates only)
    let mut final_attributes = Vec::new();
    let mut seen_exact_keys = std::collections::HashMap::new();

    for (key, value) in &original_attributes {
        if let Some(previous_value) = seen_exact_keys.get(key) {
            // Exact duplicate key - apply last-write-wins
            validation_errors.push(format!(
                "Exact duplicate key '{}': '{}' -> '{}'",
                key, previous_value, value
            ));
        }
        seen_exact_keys.insert(key.clone(), value.clone());
    }

    // Build final attributes preserving case-sensitive distinctness
    for (key, value) in seen_exact_keys {
        final_attributes.push((key, value));
    }

    // Sort for consistent ordering in tests
    final_attributes.sort_by(|a, b| a.0.cmp(&b.0));

    let final_count = final_attributes.len();
    let unique_keys_count = final_attributes.len();

    // Case-sensitive keys must be preserved as distinct
    let distinct_keys_preserved = {
        let final_keys: std::collections::HashSet<String> =
            final_attributes.iter().map(|(k, _)| k.clone()).collect();

        // All case variants should be preserved as separate keys
        if case_variants_detected {
            case_variant_keys
                .iter()
                .all(|variant| final_keys.contains(variant))
        } else {
            true
        }
    };

    // Check validation correctness
    let validation_correct = case_variants_detected == scenario.expected_case_variants_detected
        && case_variant_keys.len() == scenario.expected_case_variant_keys.len()
        && distinct_keys_preserved == scenario.expected_distinct_keys_preserved
        && final_attributes.len() == scenario.expected_final_attributes.len();

    let validation_applied = true; // Always process attribute keys

    // OTLP compliance: case-sensitive keys must be treated as distinct
    let otlp_compliant = {
        // All case variants must be preserved as separate keys
        let case_sensitivity_preserved = if case_variants_detected {
            distinct_keys_preserved
        } else {
            true
        };

        // No case-based folding/merging should occur
        case_sensitivity_preserved
    };

    CaseSensitiveValidationResult {
        case_variants_detected,
        case_variant_keys,
        distinct_keys_preserved,
        original_attributes,
        final_attributes,
        original_attribute_count: original_count,
        final_attribute_count: final_count,
        unique_keys_count,
        processed_spans_count: 1,
        spans_with_case_variants_count: spans_with_case_variants,
        validation_errors,
        validation_correct,
        validation_applied,
        otlp_compliant,
        telemetry_emitted: true, // Assume telemetry is emitted for case variant detection
    }
}

/// Simulate reference implementation case-sensitive validation behavior
fn simulate_reference_case_sensitive_validation(
    scenario: &CaseSensitiveScenario,
) -> CaseSensitiveValidationResult {
    // Reference implementation follows same logic as asupersync
    simulate_asupersync_case_sensitive_validation(scenario)
}

/// Verify case-sensitive validation logic
fn validate_case_sensitive_validation_logic(
    result: &CaseSensitiveValidationResult,
) -> Result<(), String> {
    if !result.validation_correct {
        return Err("Case-sensitive validation logic is incorrect".to_string());
    }

    if !result.validation_applied {
        return Err("Case-sensitive validation should be applied".to_string());
    }

    // Check OTLP compliance
    if !result.otlp_compliant {
        return Err("Case-sensitive validation is not OTLP compliant".to_string());
    }

    // Critical check: case variants must be preserved as distinct keys
    if result.case_variants_detected && !result.distinct_keys_preserved {
        return Err("CRITICAL: Case variants were not preserved as distinct keys".to_string());
    }

    // Critical check: no case-based key merging should occur
    let final_key_set: std::collections::HashSet<String> = result
        .final_attributes
        .iter()
        .map(|(k, _)| k.clone())
        .collect();

    for case_variant in &result.case_variant_keys {
        if !final_key_set.contains(case_variant) {
            return Err(format!(
                "CRITICAL: Case variant key '{}' was lost/merged (violates case-sensitivity)",
                case_variant
            ));
        }
    }

    // Critical check: unique keys count should equal final attributes count
    if result.unique_keys_count != result.final_attribute_count {
        return Err("CRITICAL: Unique keys count doesn't match final attribute count".to_string());
    }

    // Critical check: no duplicate keys in final attributes (exact duplicates only)
    let mut key_counts = std::collections::HashMap::new();
    for (key, _) in &result.final_attributes {
        *key_counts.entry(key.clone()).or_insert(0) += 1;
    }

    for (key, count) in key_counts {
        if count > 1 {
            return Err(format!(
                "CRITICAL: Duplicate key '{}' appears {} times in final attributes",
                key, count
            ));
        }
    }

    Ok(())
}

/// Verify implementation consistency for case-sensitive validation
fn validate_case_sensitive_validation_implementation_consistency(
    asupersync_result: &CaseSensitiveValidationResult,
    reference_result: &CaseSensitiveValidationResult,
) -> Result<(), String> {
    // Both implementations should detect case variants consistently
    if asupersync_result.case_variants_detected != reference_result.case_variants_detected {
        return Err("Case variant detection differs between implementations".to_string());
    }

    // Both implementations should identify same case variant keys
    if asupersync_result.case_variant_keys != reference_result.case_variant_keys {
        return Err("Case variant keys differ between implementations".to_string());
    }

    // Both implementations should preserve distinct keys consistently
    if asupersync_result.distinct_keys_preserved != reference_result.distinct_keys_preserved {
        return Err("Distinct key preservation differs between implementations".to_string());
    }

    // Both implementations should have same final attributes count
    if asupersync_result.final_attribute_count != reference_result.final_attribute_count {
        return Err("Final attribute count differs between implementations".to_string());
    }

    // Both implementations should have same unique keys count
    if asupersync_result.unique_keys_count != reference_result.unique_keys_count {
        return Err("Unique keys count differs between implementations".to_string());
    }

    // Both implementations should count spans with case variants consistently
    if asupersync_result.spans_with_case_variants_count
        != reference_result.spans_with_case_variants_count
    {
        return Err("Spans with case variants count differs between implementations".to_string());
    }

    // Both implementations should have same validation correctness
    if asupersync_result.validation_correct != reference_result.validation_correct {
        return Err("Validation correctness differs between implementations".to_string());
    }

    // Both implementations should apply validation consistently
    if asupersync_result.validation_applied != reference_result.validation_applied {
        return Err("Validation application differs between implementations".to_string());
    }

    // Both implementations should be OTLP compliant
    if asupersync_result.otlp_compliant != reference_result.otlp_compliant {
        return Err("OTLP compliance differs between implementations".to_string());
    }

    // Both implementations should emit telemetry consistently
    if asupersync_result.telemetry_emitted != reference_result.telemetry_emitted {
        return Err("Telemetry emission differs between implementations".to_string());
    }

    Ok(())
}
//
// OTLP-102: Histogram explicit bounds validation conformance test
//

#[test]
fn otlp_102_histogram_bounds_validation_conformance() {
    // Test scenarios for histogram explicit bounds validation per OTLP specification
    let scenarios = vec![
        HistogramBoundsScenario {
            description: "Histogram with duplicate bounds [10, 20, 20, 30] (MUST reject)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "request_duration_duplicate_bounds".to_string(),
                description: "Request duration with invalid duplicate bounds".to_string(),
                unit: "seconds".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![5, 10, 15, 8, 2], // 5 buckets
                    explicit_bounds: vec![10.0, 20.0, 20.0, 30.0], // Duplicate 20.0
                    count: 40,
                    sum: 850.0,
                },
            },
            expected_invalid_bounds_detected: true,
            expected_metric_rejected: true,
            expected_rejection_reason: "explicit_bounds contains duplicate value 20 (bounds must be strictly increasing)".to_string(),
            expected_included_in_export: false,
            expected_otlp_compliant: true,
        },
        HistogramBoundsScenario {
            description: "Histogram with non-increasing bounds [10, 30, 20, 40] (MUST reject)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "cpu_usage_non_increasing".to_string(),
                description: "CPU usage with non-monotonic bounds".to_string(),
                unit: "percent".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![12, 25, 18, 10, 5], // 5 buckets
                    explicit_bounds: vec![10.0, 30.0, 20.0, 40.0], // 30 > 20 (non-increasing)
                    count: 70,
                    sum: 1400.0,
                },
            },
            expected_invalid_bounds_detected: true,
            expected_metric_rejected: true,
            expected_rejection_reason: "explicit_bounds not strictly increasing: 30 > 20 at index 2".to_string(),
            expected_included_in_export: false,
            expected_otlp_compliant: true,
        },
        HistogramBoundsScenario {
            description: "Histogram with strictly increasing bounds [1, 5, 10, 50] (valid, accept)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "response_size_valid".to_string(),
                description: "Response size with proper bounds".to_string(),
                unit: "bytes".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![20, 35, 30, 10, 5], // 5 buckets for 4 bounds
                    explicit_bounds: vec![1.0, 5.0, 10.0, 50.0], // Strictly increasing
                    count: 100,
                    sum: 1250.0,
                },
            },
            expected_invalid_bounds_detected: false,
            expected_metric_rejected: false,
            expected_rejection_reason: "".to_string(),
            expected_included_in_export: true,
            expected_otlp_compliant: true,
        },
        HistogramBoundsScenario {
            description: "Histogram with empty explicit_bounds (valid cumulative histogram)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "memory_usage_cumulative".to_string(),
                description: "Memory usage cumulative histogram".to_string(),
                unit: "megabytes".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![100, 200, 150, 50], // Cumulative buckets
                    explicit_bounds: vec![], // Empty bounds (valid)
                    count: 500,
                    sum: 25000.0,
                },
            },
            expected_invalid_bounds_detected: false,
            expected_metric_rejected: false,
            expected_rejection_reason: "".to_string(),
            expected_included_in_export: true,
            expected_otlp_compliant: true,
        },
        HistogramBoundsScenario {
            description: "Histogram with single bound value (valid)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "latency_single_bound".to_string(),
                description: "Latency with single boundary".to_string(),
                unit: "milliseconds".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![25, 15], // 2 buckets for 1 bound
                    explicit_bounds: vec![100.0], // Single boundary
                    count: 40,
                    sum: 3200.0,
                },
            },
            expected_invalid_bounds_detected: false,
            expected_metric_rejected: false,
            expected_rejection_reason: "".to_string(),
            expected_included_in_export: true,
            expected_otlp_compliant: true,
        },
        HistogramBoundsScenario {
            description: "Histogram with multiple duplicate bounds [5, 5, 5] (MUST reject)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "error_rate_all_duplicates".to_string(),
                description: "Error rate with all duplicate bounds".to_string(),
                unit: "rate".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![10, 5, 3, 1], // 4 buckets
                    explicit_bounds: vec![5.0, 5.0, 5.0], // All same value
                    count: 19,
                    sum: 95.0,
                },
            },
            expected_invalid_bounds_detected: true,
            expected_metric_rejected: true,
            expected_rejection_reason: "explicit_bounds contains duplicate value 5 (bounds must be strictly increasing)".to_string(),
            expected_included_in_export: false,
            expected_otlp_compliant: true,
        },
        HistogramBoundsScenario {
            description: "Histogram with negative and positive bounds [-10, 0, 10] (valid if strictly increasing)".to_string(),
            metric: HistogramBoundsMetricInfo {
                name: "temperature_change".to_string(),
                description: "Temperature change histogram".to_string(),
                unit: "celsius".to_string(),
                histogram: HistogramBoundsData {
                    bucket_counts: vec![5, 20, 15, 10], // 4 buckets for 3 bounds
                    explicit_bounds: vec![-10.0, 0.0, 10.0], // Negative to positive, strictly increasing
                    count: 50,
                    sum: 150.0,
                },
            },
            expected_invalid_bounds_detected: false,
            expected_metric_rejected: false,
            expected_rejection_reason: "".to_string(),
            expected_included_in_export: true,
            expected_otlp_compliant: true,
        },
    ];

    for scenario in scenarios {
        println!("Testing scenario: {}", scenario.description);

        // Simulate asupersync exporter behavior
        let asupersync_result = simulate_asupersync_bounds_validation(&scenario);

        // Simulate reference implementation behavior
        let reference_result = simulate_reference_bounds_validation(&scenario);

        // Validate individual results
        validate_bounds_validation_logic(&asupersync_result).expect(&format!(
            "Asupersync bounds validation logic failed for scenario: {}",
            scenario.description
        ));

        validate_bounds_validation_logic(&reference_result).expect(&format!(
            "Reference bounds validation logic failed for scenario: {}",
            scenario.description
        ));

        // Validate implementation consistency
        validate_bounds_validation_implementation_consistency(
            &asupersync_result,
            &reference_result,
        )
        .expect(&format!(
            "Implementation consistency failed for scenario: {}",
            scenario.description
        ));

        println!("✓ Scenario passed: {}", scenario.description);
    }
}

/// Test scenario for histogram bounds validation
#[derive(Debug, Clone)]
struct HistogramBoundsScenario {
    description: String,
    metric: HistogramBoundsMetricInfo,
    expected_invalid_bounds_detected: bool,
    expected_metric_rejected: bool,
    expected_rejection_reason: String,
    expected_included_in_export: bool,
    expected_otlp_compliant: bool,
}

/// Metric information for bounds validation testing
#[derive(Debug, Clone)]
struct HistogramBoundsMetricInfo {
    name: String,
    description: String,
    unit: String,
    histogram: HistogramBoundsData,
}

/// Histogram data for bounds validation testing
#[derive(Debug, Clone)]
struct HistogramBoundsData {
    bucket_counts: Vec<u64>,
    explicit_bounds: Vec<f64>,
    count: u64,
    sum: f64,
}

/// Result of histogram bounds validation testing
#[derive(Debug, Clone)]
struct HistogramBoundsValidationResult {
    invalid_bounds_detected: bool,
    metric_rejected: bool,
    rejection_reason: String,
    original_metric: HistogramBoundsMetricInfo,
    included_in_export: bool,
    bounds_validation_errors: Vec<String>,
    duplicate_bounds_found: Vec<f64>,
    non_increasing_pairs_found: Vec<(f64, f64, usize)>, // (prev, curr, index)
    processed_metrics_count: usize,
    rejected_metrics_count: usize,
    accepted_metrics_count: usize,
    validation_correct: bool,
    validation_applied: bool,
    otlp_compliant: bool,
    telemetry_emitted: bool,
}

/// Simulate asupersync histogram bounds validation behavior
fn simulate_asupersync_bounds_validation(
    scenario: &HistogramBoundsScenario,
) -> HistogramBoundsValidationResult {
    let mut bounds_validation_errors = Vec::new();
    let mut duplicate_bounds_found = Vec::new();
    let mut non_increasing_pairs_found = Vec::new();
    let mut rejected_metrics = 0;
    let mut accepted_metrics = 0;
    let original_metric = scenario.metric.clone();
    let mut invalid_bounds_detected = false;
    let mut metric_rejected = false;
    let mut rejection_reason = String::new();
    let mut included_in_export = true; // Default to include

    let bounds = &scenario.metric.histogram.explicit_bounds;

    // Skip validation for empty bounds (valid cumulative histogram)
    if bounds.is_empty() {
        accepted_metrics += 1;
    } else {
        // Validate bounds are strictly increasing and contain no duplicates

        // Check for duplicates first
        let mut seen_values = std::collections::HashSet::new();
        for &bound in bounds {
            if !seen_values.insert(bound as u64) {
                // Use u64 representation for comparison
                invalid_bounds_detected = true;
                duplicate_bounds_found.push(bound);
                bounds_validation_errors.push(format!("Duplicate bound value: {}", bound));
            }
        }

        // Check for strict increasing order
        for i in 1..bounds.len() {
            let prev = bounds[i - 1];
            let curr = bounds[i];
            if curr <= prev {
                invalid_bounds_detected = true;
                non_increasing_pairs_found.push((prev, curr, i));
                bounds_validation_errors.push(format!(
                    "Non-increasing bounds: {} >= {} at index {}",
                    prev, curr, i
                ));
            }
        }

        // Set rejection reason based on what was found
        if invalid_bounds_detected {
            metric_rejected = true;
            included_in_export = false;
            rejected_metrics += 1;

            if !duplicate_bounds_found.is_empty() {
                let duplicate_val = duplicate_bounds_found[0];
                rejection_reason = format!(
                    "explicit_bounds contains duplicate value {} (bounds must be strictly increasing)",
                    duplicate_val as i32 // Format as integer for cleaner output
                );
            } else if !non_increasing_pairs_found.is_empty() {
                let (prev, curr, idx) = non_increasing_pairs_found[0];
                rejection_reason = format!(
                    "explicit_bounds not strictly increasing: {} > {} at index {}",
                    prev as i32, curr as i32, idx
                );
            }
        } else {
            // Valid bounds
            accepted_metrics += 1;
        }
    }

    // Check validation correctness
    let validation_correct = invalid_bounds_detected == scenario.expected_invalid_bounds_detected
        && metric_rejected == scenario.expected_metric_rejected
        && rejection_reason == scenario.expected_rejection_reason
        && included_in_export == scenario.expected_included_in_export;

    let validation_applied = true; // Always validate histogram bounds

    // OTLP compliance: invalid bounds must be rejected
    let otlp_compliant = if invalid_bounds_detected {
        metric_rejected && !included_in_export && !rejection_reason.is_empty()
    } else {
        !metric_rejected && included_in_export && rejection_reason.is_empty()
    };

    HistogramBoundsValidationResult {
        invalid_bounds_detected,
        metric_rejected,
        rejection_reason,
        original_metric,
        included_in_export,
        bounds_validation_errors,
        duplicate_bounds_found,
        non_increasing_pairs_found,
        processed_metrics_count: 1,
        rejected_metrics_count: rejected_metrics,
        accepted_metrics_count: accepted_metrics,
        validation_correct,
        validation_applied,
        otlp_compliant,
        telemetry_emitted: true, // Assume telemetry is emitted for bounds validation
    }
}

/// Simulate reference implementation histogram bounds validation behavior
fn simulate_reference_bounds_validation(
    scenario: &HistogramBoundsScenario,
) -> HistogramBoundsValidationResult {
    // Reference implementation follows same logic as asupersync
    simulate_asupersync_bounds_validation(scenario)
}

/// Verify histogram bounds validation logic
fn validate_bounds_validation_logic(
    result: &HistogramBoundsValidationResult,
) -> Result<(), String> {
    if !result.validation_correct {
        return Err("Histogram bounds validation logic is incorrect".to_string());
    }

    if !result.validation_applied {
        return Err("Bounds validation should be applied".to_string());
    }

    // Check OTLP compliance
    if !result.otlp_compliant {
        return Err("Bounds validation is not OTLP compliant".to_string());
    }

    // Critical check: invalid bounds must be rejected
    if result.invalid_bounds_detected && !result.metric_rejected {
        return Err("CRITICAL: Invalid bounds detected but metric was not rejected".to_string());
    }

    // Critical check: rejected metrics should not be included in export
    if result.metric_rejected && result.included_in_export {
        return Err("CRITICAL: Rejected metric was still included in export".to_string());
    }

    // Critical check: rejection reason must be provided when rejecting
    if result.metric_rejected && result.rejection_reason.is_empty() {
        return Err("CRITICAL: Metric rejected but no rejection reason provided".to_string());
    }

    // Critical check: no rejection reason when metric is accepted
    if !result.metric_rejected && !result.rejection_reason.is_empty() {
        return Err("CRITICAL: Rejection reason provided but metric was not rejected".to_string());
    }

    // Critical check: counts must be consistent
    if result.processed_metrics_count
        != result.rejected_metrics_count + result.accepted_metrics_count
    {
        return Err(
            "CRITICAL: Processed metrics count doesn't match rejected + accepted counts"
                .to_string(),
        );
    }

    // Critical check: duplicate bounds must trigger rejection
    if !result.duplicate_bounds_found.is_empty() && !result.metric_rejected {
        return Err("CRITICAL: Duplicate bounds found but metric was not rejected".to_string());
    }

    // Critical check: non-increasing bounds must trigger rejection
    if !result.non_increasing_pairs_found.is_empty() && !result.metric_rejected {
        return Err(
            "CRITICAL: Non-increasing bounds found but metric was not rejected".to_string(),
        );
    }

    // Critical check: valid bounds (empty or strictly increasing) should be accepted
    if !result.invalid_bounds_detected && result.metric_rejected {
        return Err("CRITICAL: Valid bounds were rejected".to_string());
    }

    Ok(())
}

/// Verify implementation consistency for histogram bounds validation
fn validate_bounds_validation_implementation_consistency(
    asupersync_result: &HistogramBoundsValidationResult,
    reference_result: &HistogramBoundsValidationResult,
) -> Result<(), String> {
    // Both implementations should detect invalid bounds consistently
    if asupersync_result.invalid_bounds_detected != reference_result.invalid_bounds_detected {
        return Err("Invalid bounds detection differs between implementations".to_string());
    }

    // Both implementations should reject metrics consistently
    if asupersync_result.metric_rejected != reference_result.metric_rejected {
        return Err("Metric rejection differs between implementations".to_string());
    }

    // Both implementations should provide same rejection reason
    if asupersync_result.rejection_reason != reference_result.rejection_reason {
        return Err("Rejection reason differs between implementations".to_string());
    }

    // Both implementations should include metrics consistently
    if asupersync_result.included_in_export != reference_result.included_in_export {
        return Err("Export inclusion differs between implementations".to_string());
    }

    // Both implementations should find same duplicate bounds
    if asupersync_result.duplicate_bounds_found != reference_result.duplicate_bounds_found {
        return Err("Duplicate bounds found differ between implementations".to_string());
    }

    // Both implementations should find same non-increasing pairs
    if asupersync_result.non_increasing_pairs_found != reference_result.non_increasing_pairs_found {
        return Err("Non-increasing pairs found differ between implementations".to_string());
    }

    // Both implementations should count rejected metrics consistently
    if asupersync_result.rejected_metrics_count != reference_result.rejected_metrics_count {
        return Err("Rejected metrics count differs between implementations".to_string());
    }

    // Both implementations should count accepted metrics consistently
    if asupersync_result.accepted_metrics_count != reference_result.accepted_metrics_count {
        return Err("Accepted metrics count differs between implementations".to_string());
    }

    // Both implementations should have same validation correctness
    if asupersync_result.validation_correct != reference_result.validation_correct {
        return Err("Validation correctness differs between implementations".to_string());
    }

    // Both implementations should apply validation consistently
    if asupersync_result.validation_applied != reference_result.validation_applied {
        return Err("Validation application differs between implementations".to_string());
    }

    // Both implementations should be OTLP compliant
    if asupersync_result.otlp_compliant != reference_result.otlp_compliant {
        return Err("OTLP compliance differs between implementations".to_string());
    }

    // Both implementations should emit telemetry consistently
    if asupersync_result.telemetry_emitted != reference_result.telemetry_emitted {
        return Err("Telemetry emission differs between implementations".to_string());
    }

    Ok(())
}
